import { Doc } from "../../components/doc";


export const Route = createFileRoute("/docs/getting-started")({ component: GettingStartedPage });

function GettingStartedPage() {
  return (
    <Layout.PageColumn>
      <Stack>
        <Badge>Docs</Badge>
        <Typo.H1>Getting Started</Typo.H1>
        <Typo.Lead color="support">
          A quick introduction to using <Typo.InlineCode>@imfusion/web-ui</Typo.InlineCode> components in your application.
        </Typo.Lead>
      </Stack>
      <Stack>
        <Typo.H3>Content</Typo.H3>
        <Typo.P color="minor">Coming soon.</Typo.P>
      </Stack>
    </Layout.PageColumn>
  );
}

