import { createFileRoute } from "@tanstack/react-router";

import { NAV_CONFIG } from "../nav-config";
import { Dashboard } from "../components/dashboard";

export const Route = createFileRoute("/")({ component: DashboardPage });

function DashboardPage() {
  return (
    <Dashboard.Layout>
      <Dashboard.Hero
        eyebrow="@imfusion/web-ui · playground"
        titleAccent="A token-driven component library,"
        titleSoft="in one import."
        lede="Tweak the knobs on the right to feel how a single hue change ripples through every surface, intent, and primitive. The component implementation is a swappable detail — these pages document the consumer surface."
      />

