import { useEffect, useState } from "react";
import { createRootRoute, Outlet } from "@tanstack/react-router";
import { TanStackRouterDevtoolsPanel } from "@tanstack/react-router-devtools";
import { TanStackDevtools } from "@tanstack/react-devtools";
import { WebUIProvider } from "@imfusion/web-ui";

import "@imfusion/web-ui/styles.css";
import "../styles.css";

import { NAV_CONFIG } from "../nav-config";
import { AppShell } from "../components/app-shell";
import { ColorSchemeToggle } from "../components/color-scheme-toggle/color-scheme-toggle";
import { KnobsPane } from "../components/knobs-pane/knobs-pane";

// Inline matchMedia listener: a generic useMediaQuery / useBreakpoint hook is
// the eventual home for this. Tracked in ROADMAP → Open. Workaround for now.
const NARROW_MQ = "(max-width: 48rem)";
const isInitiallyNarrow = () => typeof window !== "undefined" && window.matchMedia(NARROW_MQ).matches;

export const Route = createRootRoute({
  component: RootComponent
});

function RootComponent() {
  const [navOpen, setNavOpen] = useState(() => !isInitiallyNarrow());
  const [knobsOpen, setKnobsOpen] = useState(() => !isInitiallyNarrow());

  useEffect(() => {
    const mq = window.matchMedia(NARROW_MQ);
    const onChange = (e: MediaQueryListEvent) => {
      if (e.matches) {
        setNavOpen(false);
        setKnobsOpen(false);
      }
    };
    mq.addEventListener("change", onChange);
    return () => mq.removeEventListener("change", onChange);
  }, []);

  return (
    <>
      <WebUIProvider>
        <AppShell.Frame
          header={
            <AppShell.Header
              navOpen={navOpen}
              knobsOpen={knobsOpen}
              onToggleNav={() => setNavOpen(v => !v)}
              onToggleKnobs={() => setKnobsOpen(v => !v)}
              logo={
                <>
                  <strong>@imfusion/</strong>web-ui
                </>
              }
              rightSlot={<ColorSchemeToggle />}
            />
          }
          nav={navOpen ? <AppShell.Nav sections={NAV_CONFIG} /> : undefined}
          main={<Outlet />}
          aside={knobsOpen ? <KnobsPane /> : undefined}
          footer={<AppShell.Footer>@imfusion/web-ui playground</AppShell.Footer>}
        />
      </WebUIProvider>

      <TanStackDevtools
        config={{
          position: "bottom-right",
          defaultOpen: false
        }}
        plugins={[
          {
            name: "TanStack Router",
            render: <TanStackRouterDevtoolsPanel />
          }
        ]}
      />
    </>
  );
}

