import { SliderRoot, SliderControl, SliderTrack, SliderIndicator, SliderThumb } from "@imfusion/web-ui";

import classes from "./knob-slider.module.css";

interface Props {
  label: string;
  value: number;
  min: number;
  max: number;
  step: number;
  onChange: (value: number) => void;
}

export function KnobSlider({ label, value, min, max, step, onChange }: Props) {
  const displayValue = step >= 1 ? String(value) : value.toFixed(3);

  return (
    <div className={classes.root}>
      <div className={classes.header}>
        <span className={classes.label}>{label}</span>
        <span className={classes.value}>{displayValue}</span>
      </div>
      <SliderRoot value={value} min={min} max={max} step={step} onValueChange={v => onChange(Array.isArray(v) ? v[0] : v)}>
        <SliderControl>
          <SliderTrack>
            <SliderIndicator />
            <SliderThumb aria-label={label} />
          </SliderTrack>
        </SliderControl>
      </SliderRoot>
    </div>
  );
}

import { KnobSlider } from "../knob-slider/knob-slider";
import type { KnobConfig } from "../knob-config";

import classes from "./knob-intent-group.module.css";

interface Props {
  intent: string;
  hue: { knob: KnobConfig; value: number };
  chroma: { knob: KnobConfig; value: number };
  onChange: (cssVar: string, value: number) => void;
}

export function KnobIntentGroup({ intent, hue, chroma, onChange }: Props) {
  return (
    <div className={classes.root}>
      <div className={classes.header}>
        <span className={classes.dot} style={{ background: `oklch(0.6 ${chroma.value} ${hue.value})` }} />
        <span className={classes.name}>{intent}</span>
      </div>
      <KnobSlider
        label={hue.knob.label}
        value={hue.value}
        min={hue.knob.min}
        max={hue.knob.max}
        step={hue.knob.step}
        onChange={value => onChange(hue.knob.cssVar, value)}
      />
      <KnobSlider
        label={chroma.knob.label}
        value={chroma.value}
        min={chroma.knob.min}
        max={chroma.knob.max}
        step={chroma.knob.step}
        onChange={value => onChange(chroma.knob.cssVar, value)}
      />
    </div>
  );
}

import classes from "./generated-css-panel.module.css";

interface Props {
  cssText: string;
  onCopy: () => void;
}

export function GeneratedCssPanel({ cssText, onCopy }: Props) {
  const hasOverrides = cssText.length > 0;

  return (
    <div className={classes.root}>
      <div className={classes.header}>
        <span className={classes.title}>Generated CSS</span>
        {hasOverrides && (
          <button className={classes.copy} onClick={onCopy}>
            Copy
          </button>
        )}
      </div>
      <div className={classes.body}>
        {hasOverrides ? (
          <pre className={classes.code}>{cssText}</pre>
        ) : (
          <span className={classes.empty}>No overrides — all tokens at default values</span>
        )}
      </div>
    </div>
  );
}

import type { KnobConfig } from "./knob-config";

export function formatTokenOverrides(catalog: readonly KnobConfig[], values: Record<string, number>): string {
  const overrides = catalog.filter(k => values[k.cssVar] !== k.defaultValue);
  if (overrides.length === 0) return "";

  const lines = overrides.map(k => {
    const val = values[k.cssVar];
    const formatted = k.step >= 1 ? String(val) : val.toFixed(3);
    return `  ${k.cssVar}: ${formatted};`;
  });

  return `:root {\n${lines.join("\n")}\n}`;
}

