/* =============================================================
   Livery — Size tokens
   A single measurement scale for spacing, sizing, and layout.
   Mirrors the open-props scale (props.sizes.css).
   Reference: https://github.com/argyleink/open-props/blob/main/src/props.sizes.css
   ============================================================= */

:root {
  /* Negative space */
  --lvr-size-000: -0.5rem;
  --lvr-size-00: -0.25rem;

  /* Standard scale */
  --lvr-size-1: 0.25rem;
  --lvr-size-2: 0.5rem;
  --lvr-size-3: 1rem;
  --lvr-size-4: 1.25rem;
  --lvr-size-5: 1.5rem;
  --lvr-size-6: 1.75rem;
  --lvr-size-7: 2rem;
  --lvr-size-8: 3rem;
  --lvr-size-9: 4rem;
  --lvr-size-10: 5rem;
  --lvr-size-11: 7.5rem;
  --lvr-size-12: 10rem;
  --lvr-size-13: 15rem;
  --lvr-size-14: 20rem;
  --lvr-size-15: 30rem;

  /* Content-width clamps */
  --lvr-size-content-1: 20ch;
  --lvr-size-content-2: 45ch;
  --lvr-size-content-3: 60ch;
  --lvr-size-content-4: 90ch;
  --lvr-size-content-5: 120ch;

  --lvr-size-header-1: 20ch;
  --lvr-size-header-2: 25ch;
  --lvr-size-header-3: 35ch;
}

/* =============================================================
   Livery — Border & radius tokens
   Mirrors the open-props numeric scale (props.borders.css).
   Reference: https://github.com/argyleink/open-props/blob/main/src/props.borders.css
   ============================================================= */

:root {
  /* Border widths */
  --lvr-border-size-1: 1px;
  --lvr-border-size-2: 2px;
  --lvr-border-size-3: 5px;
  --lvr-border-size-4: 10px;
  --lvr-border-size-5: 25px;

  /* Corner radii */
  --lvr-radius-1: 2px;
  --lvr-radius-2: 5px;
  --lvr-radius-3: 1rem;
  --lvr-radius-4: 2rem;
  --lvr-radius-5: 4rem;
  --lvr-radius-6: 8rem;
  --lvr-radius-round: 1e5px;
}

/* =============================================================
   Livery — Animation duration tokens
   Mirrors the Brainly UX motion scale from open-props extra/durations.css.
   Reference: https://github.com/argyleink/open-props/blob/main/src/extra/durations.css
   ============================================================= */

:root {
  --lvr-duration-instant: 0ms;
  --lvr-duration-quick-1: 80ms;
  --lvr-duration-quick-2: 120ms;
  --lvr-duration-moderate-1: 180ms;
  --lvr-duration-moderate-2: 260ms;
  --lvr-duration-gentle-1: 320ms;
  --lvr-duration-gentle-2: 420ms;
  --lvr-duration-slow-1: 600ms;
  --lvr-duration-slow-2: 800ms;
  --lvr-duration-slow-3: 1000ms;
  --lvr-duration-slow-4: 1500ms;
  --lvr-duration-slow-5: 2000ms;
}

/* =============================================================
   Livery — Easing tokens
   Mirrors the open-props scale (props.easing.css).
   Reference: https://github.com/argyleink/open-props/blob/main/src/props.easing.css
   ============================================================= */

:root {
  /* Standard (ease out — decelerate into rest) */
  --lvr-ease-1: cubic-bezier(0.25, 0, 0.5, 1);
  --lvr-ease-2: cubic-bezier(0.25, 0, 0.4, 1);
  --lvr-ease-3: cubic-bezier(0.25, 0, 0.3, 1);
  --lvr-ease-4: cubic-bezier(0.25, 0, 0.2, 1);
  --lvr-ease-5: cubic-bezier(0.25, 0, 0.1, 1);

  /* Ease-in (accelerate into action) */
  --lvr-ease-in-1: cubic-bezier(0.25, 0, 1, 1);
  --lvr-ease-in-2: cubic-bezier(0.5, 0, 1, 1);
  --lvr-ease-in-3: cubic-bezier(0.7, 0, 1, 1);
  --lvr-ease-in-4: cubic-bezier(0.9, 0, 1, 1);
  --lvr-ease-in-5: cubic-bezier(1, 0, 1, 1);

  /* Ease-out (decelerate into rest) */
  --lvr-ease-out-1: cubic-bezier(0, 0, 0.75, 1);
  --lvr-ease-out-2: cubic-bezier(0, 0, 0.5, 1);
  --lvr-ease-out-3: cubic-bezier(0, 0, 0.3, 1);
  --lvr-ease-out-4: cubic-bezier(0, 0, 0.1, 1);
  --lvr-ease-out-5: cubic-bezier(0, 0, 0.05, 1);
}

/* =============================================================
   Livery — Layer (z-index) tokens
   Linear 1–5 scale for stacking contexts + an escape-hatch value.
   ============================================================= */

:root {
  --lvr-layer-1: 1;
  --lvr-layer-2: 2;
  --lvr-layer-3: 3;
  --lvr-layer-4: 4;
  --lvr-layer-5: 5;
  --lvr-layer-important: 999;
}

