    overflow: hidden;
    border-radius: var(--lvr-radius-1);
    background-color: var(--lvr-color-bg-accent);
}

.indicator {
    display: block;
    height: 100%;
    transition: all var(--lvr-duration-gentle-1) var(--lvr-ease-3);
}

.indicatorIdle {
    background-color: var(--lvr-color-bg-disabled);
}

.indicatorRunning {
    background-color: var(--lvr-color-bg-warn);
}

.indicatorDone {
    background-color: var(--lvr-color-bg-positive);
}

.indicatorError {
    background-color: var(--lvr-color-bg-negative);
}

.group {
