import styles from "./app-header.module.css";

interface AppHeaderProps {
    version: string;
}

export function AppHeader({ version }: AppHeaderProps) {
    return (
        <div data-component="app-header" className={styles.root}>
            <h1 className={styles.title}>
                Black Atom Livery <span className={styles.version}>v{version}</span>
            </h1>
            <p className={styles.subtitle}>Paint your Cockpit</p>
        </div>
    );
}

import { cva } from "cva";
import type { ThemeDefinition } from "@black-atom/core";
import styles from "./theme-detail.module.css";

const badgeVariants = cva({
    base: styles.badge,
    variants: {
        appearance: {
            dark: styles.badgeDark,
            light: styles.badgeLight,
        },
    },
});

interface ThemeDetailProps {
    theme: ThemeDefinition | undefined;
}

export function ThemeDetail({ theme }: ThemeDetailProps) {
    if (!theme) {
        return <div className={styles.empty}>No theme selected</div>;
    }

    const name = theme.meta.name;
    const appearance = theme.meta.appearance;
    const collection = theme.meta.collection.label;

    return (
        <div data-component="theme-detail">
            <h2 className={styles.heading}>
                {name}{" "}
                <span className={badgeVariants({ appearance })}>
                    {appearance}
                </span>
            </h2>
            <p className={styles.collection}>{collection}</p>
        </div>
    );
}

import { cva } from "cva";
import type { ThemeGroup } from "../lib/themes.ts";
import styles from "./theme-list.module.css";

const itemVariants = cva({
    base: styles.item,
    variants: {
        selected: {
            true: styles.selected,
        },
    },
});

interface ThemeListProps {
    groups: ThemeGroup[];
    selectedIndex: number;
    onSelect: (index: number) => void;
}

export function ThemeList({ groups, selectedIndex, onSelect }: ThemeListProps) {
    let flatIndex = 0;

    return (
        <div data-component="theme-list">
            {groups.map((group) => {
                const items = group.themes.map((entry) => {
                    const index = flatIndex++;
                    const isSelected = index === selectedIndex;
                    const name = entry.meta.name;
                    const icon = entry.meta.appearance === "dark" ? "☾" : "☀";

                    return (
                        <button
                            key={entry.meta.key}
                            ref={isSelected
                                ? (el) => el?.scrollIntoView({ block: "nearest" })
                                : undefined}
                            type="button"
                            onClick={() => onSelect(index)}
                            className={itemVariants({ selected: isSelected })}
                        >
                            {isSelected ? "> " : "  "}
                            {name}
                            <span className={styles.icon}>{icon}</span>
                        </button>
                    );
                });

                return (
                    <div key={group.collectionKey} className={styles.group}>
                        <div className={styles.groupLabel}>
                            {group.label} ({group.themes.length})
                        </div>
                        {items}
                    </div>
                );
            })}
        </div>
    );
}

import { cva } from "cva";
import { Progress } from "@base-ui/react/progress";
import type { UpdateResult } from "../lib/updaters.ts";
import { getProgressState } from "../lib/progress.ts";
import styles from "./progress-bar.module.css";

const indicatorVariants = cva({
    base: styles.indicator,
    variants: {
        status: {
            idle: styles.indicatorIdle,
            running: styles.indicatorRunning,
            done: styles.indicatorDone,
            error: styles.indicatorError,
        },
    },
});

interface ProgressBarProps {
    results: UpdateResult[];
}

export function ProgressBar({ results }: ProgressBarProps) {
    const { value, completedCount, total, currentLabel, status, totalDurationMs } =
        getProgressState(results);

    const labelText = status === "running" && currentLabel
        ? `Applying ${currentLabel}...`
        : status === "done"
        ? "Done"
        : status === "error"
        ? "Completed with errors"
        : "Waiting...";

    return (
        <Progress.Root
            data-component="progress-bar"
            className={styles.root}
            value={value}
            max={100}
        >
            <Progress.Label className={styles.label}>
                {labelText}
            </Progress.Label>
            <span className={styles.counter}>
                {completedCount} / {total}
                {totalDurationMs != null && status !== "running" ? ` (${totalDurationMs}ms)` : ""}
            </span>
            <Progress.Track className={styles.track}>
                <Progress.Indicator
                    className={indicatorVariants({ status })}
                />
            </Progress.Track>
        </Progress.Root>
    );
}

interface Shortcut {
    key: string;
    label: string;
}

const SHORTCUTS: Shortcut[] = [
    { key: "↑/↓ j/k", label: "navigate" },
    { key: "gg/G", label: "top/bottom" },
    { key: "Enter", label: "select" },
    { key: "q", label: "quit" },
];

export function AppFooter() {
    return (
        <div className="flex gap-6">
            {SHORTCUTS.map((s) => (
                <span key={s.key}>
                    <kbd className="text-neutral-300">{s.key}</kbd>{" "}
                    <span className="text-neutral-500">{s.label}</span>
                </span>
            ))}
        </div>
    );
}

